#  Quick PyPI Publication Script\n# Run these commands to publish QuantLib Pro to PyPI\n\nWrite-Host \" QuantLib Pro PyPI Publication Script\" -ForegroundColor Green\nWrite-Host \"=========================================\" -ForegroundColor Green\n\n# Step 1: Install build tools\nWrite-Host \"`n1. Installing build tools...\" -ForegroundColor Yellow\npip install --upgrade build twine\n\n# Step 2: Clean previous builds  \nWrite-Host \"`n2. Cleaning previous builds...\" -ForegroundColor Yellow\nRemove-Item -Recurse -Force dist, build, *.egg-info -ErrorAction SilentlyContinue\nWrite-Host \"   Cleaned build artifacts\" -ForegroundColor Gray\n\n# Step 3: Build the package\nWrite-Host \"`n3. Building package...\" -ForegroundColor Yellow\npython -m build\n\nif ($LASTEXITCODE -eq 0) {\n    Write-Host \"    Package built successfully\" -ForegroundColor Green\n} else {\n    Write-Host \"    Build failed\" -ForegroundColor Red\n    exit 1\n}\n\n# Step 4: Check the build\nWrite-Host \"`n4. Checking build quality...\" -ForegroundColor Yellow\ntwine check dist/*\n\nif ($LASTEXITCODE -eq 0) {\n    Write-Host \"    Package check passed\" -ForegroundColor Green\n} else {\n    Write-Host \"    Package check failed\" -ForegroundColor Red\n    exit 1\n}\n\n# Step 5: Show build contents\nWrite-Host \"`n5. Build contents:\" -ForegroundColor Yellow\nGet-ChildItem dist/ | ForEach-Object {\n    Write-Host \"    $($_.Name)\" -ForegroundColor Gray\n}\n\n# Step 6: Next steps\nWrite-Host \"`n Ready for upload!\" -ForegroundColor Green\nWrite-Host \"==================\" -ForegroundColor Green\nWrite-Host \"`nNext steps:\" -ForegroundColor White\nWrite-Host \"1. Test upload:    twine upload --repository testpypi dist/*\" -ForegroundColor Cyan\nWrite-Host \"2. Test install:   pip install --index-url https://test.pypi.org/simple/ quantlib-pro\" -ForegroundColor Cyan\nWrite-Host \"3. Production:     twine upload dist/*\" -ForegroundColor Cyan\n\nWrite-Host \"`n Don't forget:\" -ForegroundColor White\nWrite-Host \"• Create PyPI accounts (test.pypi.org and pypi.org)\" -ForegroundColor Gray\nWrite-Host \"• Generate API tokens\" -ForegroundColor Gray\nWrite-Host \"• Use credentials: username='__token__', password='your-api-token'\" -ForegroundColor Gray\n\nWrite-Host \"`n QuantLib Pro is ready for PyPI publication!\" -ForegroundColor Green